// Replaces o.R.LastAttemptUserVerificationStatuses with related.
// Sets related.R.LastAttempt's LastAttemptUserVerificationStatuses accordingly.
func (o *VerificationAttempt) SetLastAttemptUserVerificationStatuses(ctx context.Context, exec boil.ContextExecutor, insert bool, related ...*UserVerificationStatus) error {
	query := "update \"user_verification_status\" set \"last_attempt_id\" = null where \"last_attempt_id\" = $1"
	values := []interface{}{o.ID}
	if boil.IsDebug(ctx) {
		writer := boil.DebugWriterFrom(ctx)
		fmt.Fprintln(writer, query)
		fmt.Fprintln(writer, values)
	}
	_, err := exec.ExecContext(ctx, query, values...)
	if err != nil {
		return errors.Wrap(err, "failed to remove relationships before set")
	}

	if o.R != nil {
		for _, rel := range o.R.LastAttemptUserVerificationStatuses {
			queries.SetScanner(&rel.LastAttemptID, nil)
			if rel.R == nil {
				continue
			}

			rel.R.LastAttempt = nil
		}
		o.R.LastAttemptUserVerificationStatuses = nil
	}

	return o.AddLastAttemptUserVerificationStatuses(ctx, exec, insert, related...)
}

// RemoveLastAttemptUserVerificationStatuses relationships from objects passed in.
// Removes related items from R.LastAttemptUserVerificationStatuses (uses pointer comparison, removal does not keep order)
// Sets related.R.LastAttempt.
func (o *VerificationAttempt) RemoveLastAttemptUserVerificationStatuses(ctx context.Context, exec boil.ContextExecutor, related ...*UserVerificationStatus) error {
	if len(related) == 0 {
		return nil
	}

	var err error
	for _, rel := range related {
		queries.SetScanner(&rel.LastAttemptID, nil)
		if rel.R != nil {
			rel.R.LastAttempt = nil
		}
		if _, err = rel.Update(ctx, exec, boil.Whitelist("last_attempt_id")); err != nil {
			return err
		}
	}
	if o.R == nil {
		return nil
	}

	for _, rel := range related {
		for i, ri := range o.R.LastAttemptUserVerificationStatuses {
			if rel != ri {
				continue
			}

			ln := len(o.R.LastAttemptUserVerificationStatuses)
			if ln > 1 && i < ln-1 {
				o.R.LastAttemptUserVerificationStatuses[i] = o.R.LastAttemptUserVerificationStatuses[ln-1]
			}
			o.R.LastAttemptUserVerificationStatuses = o.R.LastAttemptUserVerificationStatuses[:ln-1]
			break
		}
	}

	return nil
}

